const result = $input.first().json;

if (!result || result.valid !== true) {
  throw new Error('Invalid request signature');
}

return [{ json: { hmac_valid: true } }];

const session = $input.first().json;

if (!session || !session.user_id) {
  throw new Error('Invalid or expired token');
}

const body = $('Receive Delete Request').first().json.body;

if (!body.session_id) {
  throw new Error('session_id is required');
}

const canDeleteAll = ['owner', 'admin'].includes(session.role);
const target_user_id = (canDeleteAll && body.target_user_id)
  ? body.target_user_id
  : session.user_id;

return [{
  json: {
    user_id: session.user_id,
    target_user_id,
    role: session.role,
    client_id: session.client_id,
    slug: session.slug,
    session_id: body.session_id
  }
}];

const result = $input.first().json;
const session_id = $('Check Token Valid').first().json.session_id;

if (!result || result.status !== 'ok') {
  throw new Error('Qdrant delete failed');
}

return [{ json: { deleted: true, session_id } }];
